#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

/*
 * Data Center Spine-Leaf Network Switch Simulation
 * Demonstrates non-blocking fabric and ECMP (Equal-Cost Multi-Path) routing
 * 
 * In spine-leaf architecture:
 * - Every leaf switch connects to EVERY spine switch
 * - Server-to-server traffic goes: leaf -> spine -> leaf (1 hop)
 * - ECMP distributes load across all available spine paths
 */

#define MAX_LEAF_SWITCHES 16
#define MAX_SPINE_SWITCHES 8
#define MAX_SERVERS_PER_LEAF 20

typedef struct {
 int id;
 int connected_servers[MAX_SERVERS_PER_LEAF];
 int server_count;
 int connected_spines[MAX_SPINE_SWITCHES];
 int spine_count;
} LeafSwitch;

typedef struct {
 int id;
 int connected_leaves[MAX_LEAF_SWITCHES];
 int leaf_count;
 uint64_t packet_count; // Track traffic for load balancing analysis
} SpineSwitch;

typedef struct {
 int id;
 int connected_leaf; // Which leaf switch this server connects to
} Server;

typedef struct {
 Server servers[256];
 int server_count;
 LeafSwitch leaf_switches[MAX_LEAF_SWITCHES];
 int leaf_count;
 SpineSwitch spine_switches[MAX_SPINE_SWITCHES];
 int spine_count;
} SpineLeafFabric;

/* Initialize the spine-leaf fabric */
void init_fabric(SpineLeafFabric *fabric) {
 fabric->server_count = 0;
 fabric->leaf_count = 0;
 fabric->spine_count = 0;

 // Initialize leaf switches
 for (int i = 0; i < MAX_LEAF_SWITCHES; i++) {
 fabric->leaf_switches[i].id = i;
 fabric->leaf_switches[i].server_count = 0;
 fabric->leaf_switches[i].spine_count = 0;
 }

 // Initialize spine switches
 for (int i = 0; i < MAX_SPINE_SWITCHES; i++) {
 fabric->spine_switches[i].id = i;
 fabric->spine_switches[i].leaf_count = 0;
 fabric->spine_switches[i].packet_count = 0;
 }
}

/* Build full mesh between all leaf and spine switches */
void build_spine_leaf_mesh(SpineLeafFabric *fabric, int num_leaves, int num_spines) {
 fabric->leaf_count = num_leaves;
 fabric->spine_count = num_spines;

 // Connect every leaf to every spine (full mesh)
 for (int l = 0; l < num_leaves; l++) {
 for (int s = 0; s < num_spines; s++) {
 fabric->leaf_switches[l].connected_spines[s] = s;
 fabric->leaf_switches[l].spine_count++;

 fabric->spine_switches[s].connected_leaves[l] = l;
 fabric->spine_switches[s].leaf_count++;
 }
 }

 printf("Built spine-leaf mesh: %d leaves <-> %d spines\n", num_leaves, num_spines);
 printf("Total connections: %d (full mesh)\n", num_leaves * num_spines);
}

/* Add a server to a leaf switch */
void add_server_to_leaf(SpineLeafFabric *fabric, int server_id, int leaf_id) {
 if (leaf_id >= fabric->leaf_count) {
 printf("Error: Invalid leaf ID\n");
 return;
 }

 Server *srv = &fabric->servers[fabric->server_count];
 srv->id = server_id;
 srv->connected_leaf = leaf_id;

 LeafSwitch *leaf = &fabric->leaf_switches[leaf_id];
 leaf->connected_servers[leaf->server_count] = fabric->server_count;
 leaf->server_count++;

 fabric->server_count++;
}

/* ECMP (Equal-Cost Multi-Path) routing - hash-based spine selection */
int ecmp_select_spine(int source_id, int dest_id, int num_spines) {
 /* Simple hash function combining source and destination IDs */
 uint32_t hash = (source_id * 31) + (dest_id * 17);
 return hash % num_spines;
}

/* Simulate packet forwarding from source to destination */
void forward_packet(SpineLeafFabric *fabric, int src_server_id, int dest_server_id) {
 if (src_server_id >= fabric->server_count || dest_server_id >= fabric->server_count) {
 printf("Error: Invalid server ID\n");
 return;
 }

 Server *src = &fabric->servers[src_server_id];
 Server *dst = &fabric->servers[dest_server_id];

 int src_leaf = src->connected_leaf;
 int dst_leaf = dst->connected_leaf;

 // Same leaf switch - direct communication
 if (src_leaf == dst_leaf) {
 printf("Server %d -> Server %d: Leaf Switch %d (direct)\n",
 src_server_id, dest_server_id, src_leaf);
 return;
 }

 // Different leaf switches - use ECMP to select spine
 int selected_spine = ecmp_select_spine(src_server_id, dest_server_id, fabric->spine_count);

 // Update packet count for statistics
 fabric->spine_switches[selected_spine].packet_count++;

 printf("Server %d -> Server %d: Leaf %d -> Spine %d -> Leaf %d\n",
 src_server_id, dest_server_id, src_leaf, selected_spine, dst_leaf);
}

/* Calculate and display network metrics */
void print_network_metrics(SpineLeafFabric *fabric) {
 printf("\n=== Spine-Leaf Network Metrics ===\n");
 printf("Total Servers: %d\n", fabric->server_count);
 printf("Leaf Switches: %d\n", fabric->leaf_count);
 printf("Spine Switches: %d\n", fabric->spine_count);

 // Maximum hops calculation
 int max_hops = (fabric->leaf_count > 1) ? 3 : 1; // leaf-spine-leaf = 3 devices, 2 links
 printf("Maximum Hops (diameter): %d (leaf -> spine -> leaf)\n", max_hops);

 // Path diversity
 printf("ECMP Paths Available: %d\n", fabric->spine_count);

 // Calculate total bisection bandwidth (simplified)
 int bandwidth_per_link = 100; // Gbps
 int bisection_bw = (fabric->spine_count * bandwidth_per_link * fabric->leaf_count) / 2;
 printf("Bisection Bandwidth: ~%d Gbps\n", bisection_bw);

 // Show spine utilization
 printf("\nSpine Switch Traffic Distribution:\n");
 uint64_t total_packets = 0;
 for (int i = 0; i < fabric->spine_count; i++) {
 total_packets += fabric->spine_switches[i].packet_count;
 }
 for (int i = 0; i < fabric->spine_count; i++) {
 double percentage = total_packets > 0 ? 
 (fabric->spine_switches[i].packet_count * 100.0 / total_packets) : 0;
 printf(" Spine %d: %llu packets (%.1f%%)\n", 
 i, (unsigned long long)fabric->spine_switches[i].packet_count, percentage);
 }
}

int main() {
 printf("=====================================\n");
 printf("Spine-Leaf Network Simulation\n");
 printf("=====================================\n");

 // Create a spine-leaf fabric
 SpineLeafFabric fabric;
 init_fabric(&fabric);

 // Build topology: 4 leaf switches, 4 spine switches
 build_spine_leaf_mesh(&fabric, 4, 4);

 // Add servers to leaf switches
 printf("\nAdding servers to leaf switches...\n");
 int server_id = 0;
 for (int leaf = 0; leaf < 4; leaf++) {
 for (int s = 0; s < 10; s++) { // 10 servers per leaf
 add_server_to_leaf(&fabric, server_id++, leaf);
 }
 }
 printf("Added %d servers total\n", fabric.server_count);

 // Simulate various traffic patterns
 printf("\n=== Traffic Simulation ===\n");

 // Server-to-server communications (demonstrating ECMP)
 printf("\nSame-leaf traffic:\n");
 forward_packet(&fabric, 0, 5); // Both on leaf 0
 forward_packet(&fabric, 15, 18); // Both on leaf 1

 printf("\nCross-leaf traffic (uses spine switches):\n");
 forward_packet(&fabric, 0, 25); // Leaf 0 -> Leaf 2
 forward_packet(&fabric, 10, 30); // Leaf 1 -> Leaf 3
 forward_packet(&fabric, 5, 38); // Leaf 0 -> Leaf 3

 // Simulate more traffic for ECMP distribution analysis
 printf("\nSimulating 1000 random cross-leaf communications...\n");
 for (int i = 0; i < 1000; i++) {
 int src = rand() % fabric.server_count;
 int dst = rand() % fabric.server_count;
 if (src != dst) {
 forward_packet(&fabric, src, dst);
 }
 }

 // Print network metrics
 print_network_metrics(&fabric);

 printf("\n=== Key Advantages Demonstrated ===\n");
 printf("1. Non-blocking: Every leaf connects to every spine\n");
 printf("2. Predictable latency: 2 hops between any servers\n");
 printf("3. Scalability: Add leaves for more servers, spines for more bandwidth\n");
 printf("4. Load balancing: ECMP distributes traffic across all spines\n");
 printf("5. Redundancy: Multiple equal-cost paths for fault tolerance\n");

 return 0;
}
